compute.source:
// Fixed-coupon bullet bond pricer. Solves price <-> YTM via Newton iteration
// when given the other side. Returns a stat grid + a cashflow table.
//
// Conventions:
//   freq    = coupon payments per year (1, 2, 4, 12)
//   coupon  = annual coupon rate as a decimal (e.g. 0.045 = 4.5%)
//   ytm     = yield to maturity as a decimal, freq-compounded
//   N       = number of periods = round(maturity_yrs * freq)
//   c       = coupon per period = face * coupon / freq
//   df_i    = (1 + ytm/freq)^-i
//
// Output fields:
//   ytm       (decimal, e.g. 0.045 = 4.5%)
//   price     (per face = `face` arg)
//   duration  (Macaulay, years)
//   mod_dur   (modified duration, years)
//   convexity (per 1.00 yield change, scaled by 1; report as raw)
//   dv01      (price change per 1bp parallel yield shift, sign positive)
//   cashflows (array of {period, yrs, cashflow, df, pv})

function compute(inputs) {
    var face   = +inputs.face;
    var coupon = +inputs.coupon_pct / 100;
    var T      = +inputs.maturity_yrs;
    var freq   = +inputs.freq;
    var N      = Math.max(1, Math.round(T * freq));
    var c      = face * coupon / freq;

    function priceFromYtm(y) {
        var per = y / freq;
        var pv = 0;
        for (var i = 1; i <= N; i++) {
            var cf = c + (i === N ? face : 0);
            pv += cf / Math.pow(1 + per, i);
        }
        return pv;
    }

    function solveYtm(targetPrice) {
        var y = (coupon > 0 ? coupon : 0.05);
        for (var k = 0; k < 80; k++) {
            var per = y / freq;
            var p = 0, dp = 0;
            for (var i = 1; i <= N; i++) {
                var cf = c + (i === N ? face : 0);
                var disc = Math.pow(1 + per, i);
                p += cf / disc;
                dp += -i * cf / (Math.pow(1 + per, i + 1) * freq);
            }
            var diff = p - targetPrice;
            if (Math.abs(diff) < 1e-10) break;
            if (Math.abs(dp) < 1e-12) break;
            y = y - diff / dp;
            if (y < -0.5) y = -0.5;
            if (y > 5)    y = 5;
        }
        return y;
    }

    var ytm, price;
    if (inputs.input_mode === 'yield') {
        ytm = +inputs.ytm_pct / 100;
        price = priceFromYtm(ytm);
    } else {
        price = +inputs.price;
        ytm = solveYtm(price);
    }

    var per = ytm / freq;
    var rows = [];
    var pv_total = 0, w_dur = 0, w_conv = 0;
    for (var i = 1; i <= N; i++) {
        var cf = c + (i === N ? face : 0);
        var df = Math.pow(1 + per, -i);
        var pv = cf * df;
        var t  = i / freq;
        rows.push({period: i, yrs: t, cashflow: cf, df: df, pv: pv});
        pv_total += pv;
        w_dur    += t * pv;
        w_conv   += t * (t + 1.0 / freq) * pv;
    }

    var mac_dur = pv_total > 0 ? w_dur / pv_total : 0;
    var mod_dur = mac_dur / (1 + per);
    var convexity = pv_total > 0
        ? w_conv / pv_total / Math.pow(1 + per, 2)
        : 0;
    var dv01 = mod_dur * price / 10000;

    return {
        ytm:       ytm,
        price:     price,
        duration:  mac_dur,
        mod_dur:   mod_dur,
        convexity: convexity,
        dv01:      dv01,
        cashflows: rows
    };
}

// Black-Scholes-Merton European call/put with continuous dividend yield.
// Greeks reported in user-friendly units:
//   delta : raw (dV/dS)
//   gamma : raw (d2V/dS2)
//   vega  : per 1 vol-PERCENTAGE-POINT (i.e. dV/dvol scaled / 100)
//   theta : per CALENDAR DAY (dV/dt scaled / 365)
//   rho   : per 1 rate-PERCENTAGE-POINT (i.e. dV/dr scaled / 100)
//
// `payoff` output sweeps spot from spot * (1 - sweep_pct/100) to
// spot * (1 + sweep_pct/100) at sweep_n evenly-spaced points; computes
// option value at each spot (NOT terminal payoff), then subtracts the
// CURRENT premium so the line shows mark-to-market P&L vs current spot.

function _normCdf(x) {
    var a1 =  0.254829592;
    var a2 = -0.284496736;
    var a3 =  1.421413741;
    var a4 = -1.453152027;
    var a5 =  1.061405429;
    var p  =  0.3275911;
    var sign = x < 0 ? -1 : 1;
    var ax = Math.abs(x) / Math.sqrt(2);
    var t = 1.0 / (1.0 + p * ax);
    var y = 1.0 - (((((a5 * t + a4) * t) + a3) * t + a2) * t + a1) * t * Math.exp(-ax * ax);
    return 0.5 * (1.0 + sign * y);
}

function _normPdf(x) {
    return Math.exp(-0.5 * x * x) / Math.sqrt(2 * Math.PI);
}

function _bsm(kind, S, K, T, sigma, r, q) {
    if (T <= 0 || sigma <= 0) {
        var intrinsic = kind === 'call' ? Math.max(S - K, 0) : Math.max(K - S, 0);
        return {
            price: intrinsic, delta: 0, gamma: 0,
            vega: 0, theta: 0, rho: 0
        };
    }
    var sqrtT = Math.sqrt(T);
    var d1 = (Math.log(S / K) + (r - q + 0.5 * sigma * sigma) * T) / (sigma * sqrtT);
    var d2 = d1 - sigma * sqrtT;
    var Nd1 = _normCdf(d1);
    var Nd2 = _normCdf(d2);
    var nd1 = _normPdf(d1);
    var disc_r = Math.exp(-r * T);
    var disc_q = Math.exp(-q * T);

    var price, delta, theta, rho;
    if (kind === 'call') {
        price = S * disc_q * Nd1 - K * disc_r * Nd2;
        delta = disc_q * Nd1;
        theta = (-S * disc_q * nd1 * sigma / (2 * sqrtT)
                 - r * K * disc_r * Nd2
                 + q * S * disc_q * Nd1);
        rho = K * T * disc_r * Nd2;
    } else {
        var Nmd1 = _normCdf(-d1);
        var Nmd2 = _normCdf(-d2);
        price = K * disc_r * Nmd2 - S * disc_q * Nmd1;
        delta = -disc_q * Nmd1;
        theta = (-S * disc_q * nd1 * sigma / (2 * sqrtT)
                 + r * K * disc_r * Nmd2
                 - q * S * disc_q * Nmd1);
        rho = -K * T * disc_r * Nmd2;
    }
    var gamma = disc_q * nd1 / (S * sigma * sqrtT);
    var vega  = S * disc_q * nd1 * sqrtT;
    return {
        price: price,
        delta: delta,
        gamma: gamma,
        vega:  vega / 100,        // per 1 vol-pt
        theta: theta / 365,       // per calendar day
        rho:   rho / 100          // per 1 rate-pt
    };
}

function compute(inputs) {
    var kind = String(inputs.kind || 'call');
    var S = +inputs.spot;
    var K = +inputs.strike;
    var T = +inputs.tte;
    var sigma = +inputs.vol  / 100;
    var r     = +inputs.rate / 100;
    var q     = +inputs.div  / 100;

    var g = _bsm(kind, S, K, T, sigma, r, q);

    var pct = +inputs.sweep_pct / 100;
    var n   = Math.max(11, Math.round(+inputs.sweep_n));
    if (n % 2 === 0) n += 1;
    var lo = S * (1 - pct);
    var hi = S * (1 + pct);
    var rows = [];
    for (var i = 0; i < n; i++) {
        var s = lo + (hi - lo) * (i / (n - 1));
        var v = _bsm(kind, s, K, T, sigma, r, q);
        rows.push({spot: s, pnl: v.price - g.price});
    }

    return {
        price: g.price,
        delta: g.delta,
        gamma: g.gamma,
        vega:  g.vega,
        theta: g.theta,
        rho:   g.rho,
        payoff: rows
    };
}

// Fed scenario swap rates.
//
// For each scenario column in `fomc_deltas`, compute a daily Fed funds path
// from `trade_date`, applying each FOMC meeting's bp delta the day AFTER the
// meeting. From the path, derive OIS-style swap rates (ACT/360 daily
// compounding) for spot tenors 1y..5y, forward 1y1y..4y1y, and one custom
// dated swap defined by (swap_start, swap_end).
//
// Inputs:
//   starting_ff      number           (in %, e.g. 3.84)
//   trade_date       string YYYY-MM-DD
//   swap_start       string YYYY-MM-DD
//   swap_end         string YYYY-MM-DD
//   fomc_deltas      {rows: [{key, label}], cols: [{id, label}], values: [[bp...]]}
//
// Outputs:
//   summary          {columns:[...], rows:[{tenor, <scen1>, <scen2>, ...}, ...]}
//   ff_paths         [{date, rate, scenario}, ...]   (long form)
//
// Conventions:
//   ACT/360 daily compounding (USD OIS market convention)
//   par OIS rate over [a, b] = (CF - 1) * (360 / days_in_period) * 100  in %
//   horizon = max(swap_end - trade_date, 5y) for path generation.

function _parseDate(s) {
    if (s instanceof Date) return s;
    var t = Date.parse(s);
    if (isNaN(t)) return null;
    return new Date(t);
}

function _ymd(d) {
    var y = d.getUTCFullYear();
    var m = String(d.getUTCMonth() + 1).padStart(2, '0');
    var dd = String(d.getUTCDate()).padStart(2, '0');
    return y + '-' + m + '-' + dd;
}

function _addDays(d, n) {
    return new Date(Date.UTC(d.getUTCFullYear(), d.getUTCMonth(),
                              d.getUTCDate() + n));
}

function _diffDays(a, b) {
    return Math.round((b - a) / 86400000);
}

function _addYears(d, n) {
    return new Date(Date.UTC(d.getUTCFullYear() + n,
                              d.getUTCMonth(), d.getUTCDate()));
}

// Build daily FF rate array starting at trade_date out to horizon_end.
// step_dates: array of {date: Date, delta_bp: number} sorted ascending.
// Each meeting's delta_bp is applied the day AFTER that meeting date.
// Returns an array of length horizon_days+1, indexed by day offset from
// trade_date (0 = trade_date, 1 = trade_date + 1 day, ...).
function _buildPath(starting_pct, trade_dt, step_dates, horizon_days) {
    var path = new Array(horizon_days + 1);
    var rate = starting_pct;
    var nextStep = 0;
    for (var i = 0; i <= horizon_days; i++) {
        var d = _addDays(trade_dt, i);
        while (nextStep < step_dates.length) {
            var sd = step_dates[nextStep].date;
            // The rate changes the day AFTER the FOMC date.
            if (d > sd) {
                rate += step_dates[nextStep].delta_bp / 100;
                nextStep++;
            } else break;
        }
        path[i] = rate;
    }
    return path;
}

// Compounded factor over [from_idx, to_idx) using ACT/360 daily compounding.
function _compoundFactor(path, from_idx, to_idx) {
    var cf = 1.0;
    for (var i = from_idx; i < to_idx; i++) {
        var r = path[i] / 100; // decimal
        cf *= (1 + r / 360);
    }
    return cf;
}

// Par OIS rate over [from_idx, to_idx) -- returns rate in PERCENT.
function _parRate(path, from_idx, to_idx) {
    var days = to_idx - from_idx;
    if (days <= 0) return NaN;
    var cf = _compoundFactor(path, from_idx, to_idx);
    return (cf - 1) * (360 / days) * 100;
}

function compute(inputs) {
    var trade_dt  = _parseDate(inputs.trade_date);
    var swap_a    = _parseDate(inputs.swap_start) || trade_dt;
    var swap_b    = _parseDate(inputs.swap_end)   || _addYears(trade_dt, 3);
    var startFf   = +inputs.starting_ff;

    var matrix = inputs.fomc_deltas || {rows: [], cols: [], values: []};
    var rows = matrix.rows  || [];
    var cols = matrix.cols  || [];
    var vals = matrix.values || [];

    if (!trade_dt || cols.length === 0) {
        return {summary: {columns: [], rows: []}, ff_paths: []};
    }

    // Horizon: max of 5y and (swap_end - trade_date), plus a small buffer.
    var horizon_days = Math.max(
        _diffDays(trade_dt, _addYears(trade_dt, 5)),
        swap_b ? _diffDays(trade_dt, swap_b) : 0
    ) + 30;

    // Tenor list (years): spot 1..5, forwards 1y1y..4y1y, custom.
    var spot_tenors = [
        {id: '1y',  near: 0, far: 1},
        {id: '2y',  near: 0, far: 2},
        {id: '3y',  near: 0, far: 3},
        {id: '4y',  near: 0, far: 4},
        {id: '5y',  near: 0, far: 5},
        {id: '1y1y', near: 1, far: 2},
        {id: '2y1y', near: 2, far: 3},
        {id: '3y1y', near: 3, far: 4},
        {id: '4y1y', near: 4, far: 5}
    ];

    // For each scenario column, build path + compute rates.
    var summary_rows = [];
    var ff_paths = [];

    spot_tenors.forEach(function(t) {
        var rec = {tenor: t.id};
        cols.forEach(function() { rec[arguments[0]]; });
        summary_rows.push(rec);
    });
    summary_rows.push({tenor: 'custom'});

    var step_per_col = [];
    cols.forEach(function(col, ci) {
        // Collect this column's deltas attached to row dates.
        var steps = [];
        for (var ri = 0; ri < rows.length; ri++) {
            var row = rows[ri];
            var dt = _parseDate(row.key);
            if (!dt) continue;
            var raw = (vals[ri] || [])[ci];
            var bp = (raw == null || raw === '') ? 0 : +raw;
            if (isNaN(bp)) bp = 0;
            steps.push({date: dt, delta_bp: bp});
        }
        steps.sort(function(a, b) { return a.date - b.date; });
        step_per_col.push(steps);
    });

    cols.forEach(function(col, ci) {
        var steps = step_per_col[ci];
        var path = _buildPath(startFf, trade_dt, steps, horizon_days);

        // Spot + forward tenors.
        spot_tenors.forEach(function(t, ti) {
            var near_dt = _addYears(trade_dt, t.near);
            var far_dt  = _addYears(trade_dt, t.far);
            var ai = Math.max(0, _diffDays(trade_dt, near_dt));
            var bi = Math.min(path.length, _diffDays(trade_dt, far_dt));
            var r = _parRate(path, ai, bi);
            summary_rows[ti][col.id] = r;
        });

        // Custom dated swap.
        var ai = Math.max(0, _diffDays(trade_dt, swap_a));
        var bi = Math.min(path.length, _diffDays(trade_dt, swap_b));
        var r_custom = _parRate(path, ai, bi);
        summary_rows[summary_rows.length - 1][col.id] = r_custom;

        // FF path long-form: subsample to weekly to keep payload tight.
        var stride = 7;
        for (var i = 0; i < path.length; i += stride) {
            var d = _addDays(trade_dt, i);
            ff_paths.push({date: _ymd(d), rate: path[i], scenario: col.label || col.id});
        }
    });

    return {
        summary:  {
            columns: [
                {field: 'tenor',  label: 'Tenor',     align: 'left'}
            ].concat(cols.map(function(c) {
                return {field: c.id, label: (c.label || c.id) + ' (%)',
                          align: 'right', format: 'number:3'};
            })),
            rows: summary_rows
        },
        ff_paths: ff_paths
    };
}
